import { useEffect, useState }   from "react";
import { useForm, useFormState } from "react-hook-form";
import { useDispatch }           from "react-redux";

import { useSendFileWithDesc }     from "Helpers/Hooks";
import { FilesSlice }              from "Store/Slices";
import { AppraisalHOCPageFetcher } from "Components/Appraisal";
import UploadPictures              from "./UploadPictures";

const PARAMS = { select_fields : ["photo"] };
const DEFAULT_FETCH_DATA = {
	photo : {
		facade            : null,
		localization_map  : null,
		rear_facade       : null,
		dinning_room      : null,
		kitchen           : null,
		bathroom          : null,
		bedroom           : null,
		enviornment       : null,
		sketch_property   : null,
		bedroom_two       : null,
		microlocation     : null,
		other_description : null,
		other             : null,
	},
};

const UploadPicturesContainer = ({ appraise = DEFAULT_FETCH_DATA }) => {

	console.log(appraise);

	const [loadingFiles, setLoadingFiles] = useState(false);

	// ------------> redux <---------------
	const distpach = useDispatch();

	// ------------> RTK-Q <---------------
	const { photo } = appraise;

	const {
		facade,
		localization_map,
		rear_facade,
		dinning_room,
		kitchen,
		bathroom,
		bedroom,
		environment,
		sketch_property,
		bedroom_two,
		microlocation,
		other,
	} = photo;

	// ------------> useHookForm <---------------
	const getFile = (fileInfo) => {
		if (!fileInfo?.location) {
			return null;
		}
		const file = { ...fileInfo };
		delete file?.description;

		return file;
	};

	const defaultValues  = {
		facade : {
			file        : getFile(facade),
			description : facade?.description ?? "",
		},
		localization_map : {
			file        : getFile(localization_map),
			description : localization_map?.description ?? "",
		},
		rear_facade : {
			file        : getFile(rear_facade),
			description : rear_facade?.description ?? "",
		},
		dinning_room : {
			file        : getFile(dinning_room),
			description : dinning_room?.description ?? "",
		},
		kitchen : {
			file        : getFile(kitchen),
			description : kitchen?.description ?? "",
		},
		bathroom : {
			file        : getFile(bathroom),
			description : bathroom?.description ?? "",
		},
		bedroom : {
			file        : getFile(bedroom),
			description : bedroom?.description ?? "",
		},
		environment : {
			file        : getFile(environment),
			description : environment?.description ?? "",
		},
		sketch_property : {
			file        : getFile(sketch_property),
			description : sketch_property?.description ?? "",
		},
		bedroom_two : {
			file        : getFile(bedroom_two),
			description : bedroom_two?.description ?? "",
		},
		microlocation : {
			file        : getFile(microlocation),
			description : microlocation?.description ?? "",
		},
		other_files : other,
	};

	const hookForm = useForm({ defaultValues });

	const { handleSubmit, control } = hookForm;

	const { dirtyFields } = useFormState({ control });

	// ------------> submitData <---------------

	const isDirtyFiles = () => {
		const isDirtySomeFile = dirtyFields?.facade?.file
		|| dirtyFields?.localization_map?.file
		|| dirtyFields?.rear_facade?.file
		|| dirtyFields?.dinning_room?.file
		|| dirtyFields?.kitchen?.file
		|| dirtyFields?.bathroom?.file
		|| dirtyFields?.bedroom?.file
		|| dirtyFields?.environment?.file
		|| dirtyFields?.sketch_property?.file
		|| dirtyFields?.bedroom_two?.file
		|| dirtyFields?.microlocation?.file
		|| dirtyFields?.other_files;

		return isDirtySomeFile;
	};

	const isDirtyDescFiles = () => {
		const isDirtySomeDesc = dirtyFields?.facade?.description
		|| dirtyFields?.localization_map?.description
		|| dirtyFields?.rear_facade?.description
		|| dirtyFields?.dinning_room?.description
		|| dirtyFields?.kitchen?.description
		|| dirtyFields?.bathroom?.description
		|| dirtyFields?.bedroom?.description
		|| dirtyFields?.environment?.description
		|| dirtyFields?.sketch_property?.description
		|| dirtyFields?.bedroom_two?.description
		|| dirtyFields?.microlocation?.description;

		return isDirtySomeDesc;
	};

	const [
		handleSubmitFiles,
		handleRemoveFiles,
		{ isLoading },
	] = useSendFileWithDesc({ dirtyFields, module : "photo" });

	const submitFiles = async (files) => {
		if (!isDirtyFiles() && !isDirtyDescFiles()) {
			return;
		}
		await handleRemoveFiles();

		await handleSubmitFiles(files);
	};

	const onSubmit = handleSubmit(async (formData) => {
		setLoadingFiles(true);
		await submitFiles(formData);
		setLoadingFiles(false);
	});

	useEffect(() => {
		return () => {
			distpach(FilesSlice.actions.clearFiles());
		};
	}, []);


	return (
		<UploadPictures
			delegations={{
				onSubmit,
				hookForm,
				isLoading : isLoading || loadingFiles,
			}}
		/>
	);
};

export default AppraisalHOCPageFetcher(UploadPicturesContainer, PARAMS);
