import { Tabs, HeaderPage } from "Components/Appraisal";
import UploadPicturesForm   from "Components/Appraisal/UploadPicturesForm";

const tabs = [
	{
		title : "Cargar Fotografías",
		Tab   : UploadPicturesForm,
	},
];

const UploadPictures = ({
	delegations : {
		onSubmit,
		hookForm,
		isLoading,
	},
}) => {

	const { formState : { isDirty } } = hookForm;

	return (
		<>
			<HeaderPage
				currentIndex={[0, 0]}
				section="footer"
				isDirty={isDirty}
				onSubmit={onSubmit}
				isSubmitingData={isLoading}
			/>
			<Tabs
				tabs={tabs}
				onSubmit={onSubmit}
				hookForm={hookForm}
				isSubmitingData={isLoading}
			/>
		</>
	);
};

export default UploadPictures;
